const data = $input.first().json;
const reports = data.reports || [];

const bridgeBuilding = reports.filter(r => ['bridge', 'building'].includes(r.custom_fields?.assetType));
const serviceDisruption = reports.filter(r => r.custom_fields?.serviceDisruption === true);
const accessRestricted = reports.filter(r => r.custom_fields?.accessRestricted === true);
const critical = reports.filter(r => r.severity === 'Critical');
const high = reports.filter(r => r.severity === 'High');

let severity = 'Low';
let probability = 0.05;
let shouldAlert = false;
let message = '';

if (bridgeBuilding.length >= 1 && (critical.length >= 1 || serviceDisruption.length >= 1)) {
  severity = 'Critical';
  probability = 0.90;
  shouldAlert = true;
  message = `CRITICAL INFRASTRUCTURE FAILURE: ${bridgeBuilding.length} bridge/building report(s). Immediate inspection required.`;
} else if (critical.length >= 2 || serviceDisruption.length >= 3) {
  severity = 'High';
  probability = 0.75;
  shouldAlert = true;
  message = `${critical.length} critical infrastructure reports. ${serviceDisruption.length} service disruptions.`;
} else if (reports.length >= 5 || high.length >= 2) {
  severity = 'Medium';
  probability = 0.50;
  shouldAlert = true;
  message = `${reports.length} infrastructure damage reports. ${accessRestricted.length} access restrictions.`;
} else if (reports.length >= 2) {
  severity = 'Low';
  probability = 0.25;
  shouldAlert = false;
  message = `${reports.length} infrastructure reports. Monitoring.`;
}

return [{ json: {
  incidentType: 'infrastructure_damage',
  severity,
  probability,
  reportCount: reports.length,
  criticalAssets: bridgeBuilding.length,
  serviceDisruptions: serviceDisruption.length,
  accessRestrictions: accessRestricted.length,
  message,
  shouldAlert,
  timestamp: new Date().toISOString()
}}];
